    const amountInDollars = total / 100;

    if (!!maximumAmount && total > maximumAmount) {
      const maximumCurrencyValue = currency(maximumAmount / 100);

      return t('transactionLimits.error.maximum', {
        maximumAmount: formatCurrency(maximumCurrencyValue.intValue, {
          hideDecimal: maximumCurrencyValue.cents() === 0,
        }),
      });
    }

    if (!!minimumAmount && amountInDollars !== 0 && amountInDollars < minimumAmount) {
      const minimumCurrencyValue = currency(minimumAmount);

      return t('transactionLimits.error.minimum', {
        minimumAmount: formatCurrency(minimumCurrencyValue.intValue, {
          hideDecimal: minimumCurrencyValue.cents() === 0,
        }),
      });
